\begin{definition*}
Let $G$ be a connected graph. A \underline{spanning tree} of $G$ is a tree
$T \subseteq G$ such that $V(T) = V(G)$.
\end{definition*}

\begin{theorem}
Every connected graph $G$ has a spanning tree.
\end{theorem}

\begin{proof}
Remove an edge from a cycle (repeatedly) until no more cycles exist.
\end{proof}
